 45→func (a *Agent) ParseHook(hookName string, input []byte) (*protocol.EventJSON, error) {
 46→	var raw hookInputRaw
 47→	if len(input) > 0 {
 48→		if err := json.Unmarshal(input, &raw); err != nil {
 49→			return nil, err
 50→		}
 51→	}
 52→
 53→	switch hookName {
 54→	case HookNameAgentSpawn:
 55→		sessionID := a.generateAndCacheSessionID()
 56→		return &protocol.EventJSON{
 57→			Type:      1,
 58→			SessionID: sessionID,
 59→			Timestamp: time.Now().UTC().Format(time.RFC3339),
 60→		}, nil
 61→	case HookNameUserPromptSubmit:
 62→		sessionID := a.readCachedSessionID()
 63→		if sessionID == "" {
 64→			sessionID = a.generateAndCacheSessionID()
 65→		}
 66→		prompt := raw.Prompt
 67→		if prompt == "" {
 68→			prompt = os.Getenv("USER_PROMPT")
 69→		}
 70→		return &protocol.EventJSON{
 71→			Type:      2,
 72→			SessionID: sessionID,
 73→			Prompt:    prompt,
 74→			Timestamp: time.Now().UTC().Format(time.RFC3339),
 75→		}, nil
 76→	case HookNamePreToolUse, HookNamePostToolUse:
 77→		return nil, nil
 78→	case HookNameStop:
 79→		cwd := raw.CWD
 80→		if cwd == "" {
 81→			cwd = protocol.RepoRoot()
 82→		}
 83→		sessionID := a.readCachedSessionID()
 84→		if sessionID == "" {
 85→			nativeSessionID, err := a.querySessionID(cwd)
 86→			if err == nil && nativeSessionID != "" {
 87→				sessionID = nativeSessionID
 88→			} else {
 89→				sessionID = fallbackStopSessionID()
 90→			}
 91→		}
 92→		sessionRef := a.captureTranscriptForStop(cwd, sessionID)
 93→		a.clearCachedSessionID()
 94→		return &protocol.EventJSON{
 95→			Type:       3,
 96→			SessionID:  sessionID,
 97→			SessionRef: sessionRef,
 98→			Timestamp:  time.Now().UTC().Format(time.RFC3339),
 99→		}, nil
100→	default:
101→		return nil, nil
102→	}
103→}
