141→	if err != nil {
142→		return "", fmt.Errorf("IDE sessions.json not found: %w", err)
143→	}
144→
145→	var sessions []ideSessionIndexEntry
146→	if err := json.Unmarshal(indexData, &sessions); err != nil {
147→		return "", fmt.Errorf("failed to parse IDE sessions.json: %w", err)
148→	}
149→	if len(sessions) == 0 {
150→		return "", errors.New("no IDE sessions found")
151→	}
152→
