163→	cachePath, err := a.cacheTranscriptPath(cwd, sessionID)
164→	if err != nil {
165→		return "", err
166→	}
167→	if err := os.WriteFile(cachePath, transcriptData, 0o600); err != nil {
168→		return "", fmt.Errorf("failed to write cached IDE transcript: %w", err)
169→	}
170→	return cachePath, nil
171→}
