468→func extractModifiedFilesFromHistory(entries []kiroHistoryEntry) []string {
469→	seen := make(map[string]bool)
470→	var files []string
471→
472→	for i := range entries {
473→		for _, path := range extractFilesFromAssistant(entries[i].Assistant) {
474→			if path == "" || seen[path] {
475→				continue
476→			}
477→			seen[path] = true
478→			files = append(files, path)
479→		}
480→	}
481→
482→	return files
483→}
484→
485→func extractFilesFromAssistant(raw json.RawMessage) []string {
486→	if len(raw) == 0 {
487→		return nil
488→	}
489→
490→	var toolUseContent kiroToolUseContent
491→	if err := json.Unmarshal(raw, &toolUseContent); err != nil || len(toolUseContent.ToolUse.ToolUses) == 0 {
492→		return nil
493→	}
494→
495→	var paths []string
496→	for _, call := range toolUseContent.ToolUse.ToolUses {
497→		if !isFileModificationTool(call.Name) {
498→			continue
499→		}
500→		if path := extractFilePath(call.Args); path != "" {
501→			paths = append(paths, path)
502→		}
503→	}
504→	return paths
505→}
506→
507→func isFileModificationTool(name string) bool {
508→	_, ok := kiroFileModificationTools[name]
509→	return ok
510→}
511→
512→func extractFilePath(args json.RawMessage) string {
513→	if len(args) == 0 {
514→		return ""
515→	}
516→
517→	var fields map[string]json.RawMessage
518→	if err := json.Unmarshal(args, &fields); err != nil {
519→		return ""
520→	}
521→
522→	for _, key := range []string{"path", "file_path", "filename"} {
523→		raw, ok := fields[key]
524→		if !ok {
525→			continue
526→		}
527→		var path string
528→		if err := json.Unmarshal(raw, &path); err == nil && path != "" {
529→			return path
530→		}
531→	}
532→	return ""
533→}
534→
535→func extractLastAssistantResponse(entries []kiroHistoryEntry) string {
536→	for i := len(entries) - 1; i >= 0; i-- {
537→		if len(entries[i].Assistant) == 0 {
538→			continue
539→		}
540→
541→		var responseContent kiroResponseContent
542→		if err := json.Unmarshal(entries[i].Assistant, &responseContent); err == nil && responseContent.Response.Content != "" {
543→			return responseContent.Response.Content
544→		}
545→	}
546→	return ""
547→}
