191→// readStdinWithTimeout reads from r but returns empty data if nothing arrives
192→// within the timeout. This prevents blocking when an IDE keeps stdin open
193→// without sending data (e.g., for hooks that have no payload).
194→func readStdinWithTimeout(r io.Reader, timeout time.Duration) ([]byte, error) {
195→	type result struct {
196→		data []byte
197→		err  error
198→	}
199→	ch := make(chan result, 1)
200→	go func() {
201→		data, err := io.ReadAll(r)
202→		ch <- result{data, err}
203→	}()
204→	select {
205→	case res := <-ch:
206→		return res.data, res.err
207→	case <-time.After(timeout):
208→		return nil, nil
209→	}
210→}
