144→// WaitForCheckpoint polls for a checkpoint on the entire/checkpoints/v1 branch.
145→// It checks for new commits on that branch within the given timeout.
146→func WaitForCheckpoint(t *testing.T, le *LifecycleEnv, timeout time.Duration) {
147→	t.Helper()
148→	deadline := time.Now().Add(timeout)
149→	for time.Now().Before(deadline) {
150→		cmd := exec.Command("git", "rev-parse", "--verify", "entire/checkpoints/v1")
151→		cmd.Dir = le.Dir
152→		cmd.Env = le.Env
153→		if err := cmd.Run(); err == nil {
154→			t.Log("checkpoint branch found")
155→			return
156→		}
157→		time.Sleep(500 * time.Millisecond)
158→	}
159→	t.Fatal("timed out waiting for checkpoint branch entire/checkpoints/v1")
160→}
161→
162→// GetCheckpointTrailer extracts the Entire-Checkpoint trailer from a commit ref.
163→func GetCheckpointTrailer(t *testing.T, le *LifecycleEnv, ref string) string {
164→	t.Helper()
165→	out := le.GitOutput(t, "log", "-1", "--format=%B", ref)
166→	for _, line := range strings.Split(out, "\n") {
167→		if strings.HasPrefix(line, "Entire-Checkpoint:") {
168→			return strings.TrimSpace(strings.TrimPrefix(line, "Entire-Checkpoint:"))
169→		}
170→	}
171→	return ""
172→}
