  1→//go:build e2e
  2→
  3→package e2e
  4→
  5→import (
  6→	"fmt"
  7→	"os"
  8→	"os/exec"
  9→	"path/filepath"
 10→	"strings"
 11→	"testing"
 12→)
 13→
 14→// agentBinaries maps agent names to their built binary paths.
 15→var agentBinaries = map[string]string{}
 16→
 17→func TestMain(m *testing.M) {
 18→	tmpDir, err := os.MkdirTemp("", "e2e-agents-*")
 19→	if err != nil {
 20→		fmt.Fprintf(os.Stderr, "failed to create temp dir: %v\n", err)
 21→		os.Exit(1)
 22→	}
 23→	defer os.RemoveAll(tmpDir)
 24→
 25→	agents, err := discoverAgents()
 26→	if err != nil {
 27→		fmt.Fprintf(os.Stderr, "failed to discover agents: %v\n", err)
 28→		os.Exit(1)
 29→	}
 30→
 31→	if len(agents) == 0 {
 32→		fmt.Fprintln(os.Stderr, "no agents found in agents/ directory")
 33→		os.Exit(1)
 34→	}
 35→
 36→	for _, agentDir := range agents {
 37→		agentName := filepath.Base(agentDir)
 38→		binPath := filepath.Join(tmpDir, agentName)
 39→		// Each agent has its own go.mod, so build from the agent's directory
 40→		agentAbsDir := filepath.Join(repoRoot(), agentDir)
 41→		mainPkg := "./cmd/" + agentName
 42→
 43→		fmt.Printf("Building %s...\n", agentName)
 44→		cmd := exec.Command("go", "build", "-o", binPath, mainPkg)
 45→		cmd.Dir = agentAbsDir
 46→		cmd.Stdout = os.Stdout
 47→		cmd.Stderr = os.Stderr
 48→		if err := cmd.Run(); err != nil {
 49→			fmt.Fprintf(os.Stderr, "failed to build %s: %v\n", agentName, err)
 50→			os.Exit(1)
 51→		}
 52→
 53→		agentBinaries[agentName] = binPath
 54→		fmt.Printf("Built %s -> %s\n", agentName, binPath)
 55→	}
 56→
 57→	// Add the temp bin directory to PATH so that `entire enable` can discover
 58→	// the agent binaries (e.g. entire-agent-kiro) during lifecycle tests.
 59→	os.Setenv("PATH", tmpDir+string(os.PathListSeparator)+os.Getenv("PATH"))
 60→
 61→	os.Exit(m.Run())
 62→}
 63→
 64→func discoverAgents() ([]string, error) {
 65→	agentsDir := filepath.Join(repoRoot(), "agents")
 66→	entries, err := os.ReadDir(agentsDir)
 67→	if err != nil {
 68→		return nil, fmt.Errorf("read agents dir: %w", err)
 69→	}
 70→
 71→	var agents []string
 72→	for _, entry := range entries {
 73→		if !entry.IsDir() {
 74→			continue
 75→		}
 76→		if !strings.HasPrefix(entry.Name(), "entire-agent-") {
 77→			continue
 78→		}
 79→		// Verify it has a cmd/<name>/main.go
 80→		mainFile := filepath.Join(agentsDir, entry.Name(), "cmd", entry.Name(), "main.go")
 81→		if _, err := os.Stat(mainFile); err != nil {
 82→			continue
 83→		}
 84→		agents = append(agents, filepath.Join("agents", entry.Name()))
 85→	}
 86→	return agents, nil
 87→}
 88→
 89→func repoRoot() string {
 90→	// Walk up from e2e/ to find the repo root
 91→	dir, err := os.Getwd()
 92→	if err != nil {
 93→		return ".."
 94→	}
 95→	// If we're in the e2e directory, go up one level
 96→	if filepath.Base(dir) == "e2e" {
 97→		return filepath.Dir(dir)
 98→	}
 99→	return dir
100→}
