 16→const (
 17→	hooksFileName       = "entire.json"
 18→	hooksDir            = "agents"
 19→	ideHooksDir         = "hooks"
 20→	ideHookFileSuffix   = ".kiro.hook"
 21→	ideHookVersion      = "1"
 22→	vscodeSettingsDir   = ".vscode"
 23→	vscodeSettingsFile  = "settings.json"
 24→	trustedCommandsKey  = "kiroAgent.trustedCommands"
 25→	prodTrustedCommand  = "sh -c 'entire hooks *"
 26→	localDevCommandBase = "go run ${KIRO_PROJECT_DIR}/cmd/entire/main.go hooks kiro "
 27→	localDevTrustedCmd  = "sh -c 'go run ${KIRO_PROJECT_DIR}/cmd/entire/main.go hooks *"
 28→	prodHookCommandBase = "entire hooks kiro "
 29→	sessionIDFile       = "kiro-active-session"
 30→)
 31→
 32→type ideHookDef struct {
 33→	Filename    string
 34→	TriggerType string
 35→	CLIVerb     string
 36→}
 37→
 38→var ideHookDefs = []ideHookDef{
 39→	{Filename: "entire-prompt-submit", TriggerType: "promptSubmit", CLIVerb: HookNameUserPromptSubmit},
 40→	{Filename: "entire-stop", TriggerType: "agentStop", CLIVerb: HookNameStop},
 41→	{Filename: "entire-pre-tool-use", TriggerType: "preToolUse", CLIVerb: HookNamePreToolUse},
 42→	{Filename: "entire-post-tool-use", TriggerType: "postToolUse", CLIVerb: HookNamePostToolUse},
 43→}
 44→
 45→func (a *Agent) ParseHook(hookName string, input []byte) (*protocol.EventJSON, error) {
 46→	var raw hookInputRaw
 47→	if len(input) > 0 {
 48→		if err := json.Unmarshal(input, &raw); err != nil {
 49→			return nil, err
 50→		}
 51→	}
 52→
 53→	switch hookName {
 54→	case HookNameAgentSpawn:
 55→		sessionID := a.generateAndCacheSessionID()
 56→		return &protocol.EventJSON{
 57→			Type:      1,
 58→			SessionID: sessionID,
 59→			Timestamp: time.Now().UTC().Format(time.RFC3339),
 60→		}, nil
 61→	case HookNameUserPromptSubmit:
 62→		sessionID := a.readCachedSessionID()
 63→		if sessionID == "" {
 64→			sessionID = a.generateAndCacheSessionID()
 65→		}
 66→		prompt := raw.Prompt
 67→		if prompt == "" {
 68→			prompt = os.Getenv("USER_PROMPT")
 69→		}
 70→		return &protocol.EventJSON{
 71→			Type:      2,
 72→			SessionID: sessionID,
 73→			Prompt:    prompt,
 74→			Timestamp: time.Now().UTC().Format(time.RFC3339),
 75→		}, nil
 76→	case HookNamePreToolUse, HookNamePostToolUse:
 77→		return nil, nil
 78→	case HookNameStop:
 79→		cwd := raw.CWD
 80→		if cwd == "" {
 81→			cwd = protocol.RepoRoot()
 82→		}
 83→		sessionID := a.readCachedSessionID()
 84→		if sessionID == "" {
 85→			nativeSessionID, err := a.querySessionID(cwd)
 86→			if err == nil && nativeSessionID != "" {
 87→				sessionID = nativeSessionID
 88→			} else {
 89→				sessionID = fallbackStopSessionID()
 90→			}
 91→		}
 92→		sessionRef := a.captureTranscriptForStop(cwd, sessionID)
 93→		a.clearCachedSessionID()
 94→		return &protocol.EventJSON{
 95→			Type:       3,
 96→			SessionID:  sessionID,
 97→			SessionRef: sessionRef,
 98→			Timestamp:  time.Now().UTC().Format(time.RFC3339),
 99→		}, nil
100→	default:
101→		return nil, nil
102→	}
103→}
104→
105→func (a *Agent) InstallHooks(localDev bool, force bool) (int, error) {
106→	repoRoot := protocol.RepoRoot()
107→	if !force && allHooksInstalled(repoRoot, localDev) && trustedCommandsPresent(repoRoot, localDev) {
108→		return 0, nil
109→	}
110→
111→	if err := writeCLIHooks(repoRoot, localDev); err != nil {
112→		return 0, err
113→	}
114→	if err := writeIDEHooks(repoRoot, localDev); err != nil {
115→		return 0, err
116→	}
117→	if err := installTrustedCommands(repoRoot, localDev); err != nil {
118→		return 0, err
119→	}
120→
121→	return len(defaultHookNames()) + len(ideHookDefs), nil
122→}
123→
124→func (a *Agent) UninstallHooks() error {
125→	repoRoot := protocol.RepoRoot()
126→	cliPath := filepath.Join(repoRoot, ".kiro", hooksDir, hooksFileName)
127→	if err := os.Remove(cliPath); err != nil && !os.IsNotExist(err) {
128→		return err
129→	}
130→	for _, def := range ideHookDefs {
131→		path := filepath.Join(repoRoot, ".kiro", ideHooksDir, def.Filename+ideHookFileSuffix)
132→		if err := os.Remove(path); err != nil && !os.IsNotExist(err) {
133→			return err
134→		}
135→	}
136→	if err := uninstallTrustedCommands(repoRoot); err != nil {
137→		return err
138→	}
139→	return nil
140→}
