142→func (a *Agent) AreHooksInstalled() bool {
143→	repoRoot := protocol.RepoRoot()
144→	if _, err := os.Stat(filepath.Join(repoRoot, ".kiro", "agents", "entire.json")); err == nil {
145→		return true
146→	}
147→	if _, err := os.Stat(filepath.Join(repoRoot, ".kiro", "hooks", "entire-stop.kiro.hook")); err == nil {
148→		return true
149→	}
150→	return false
151→}
