163→func writeCLIHooks(repoRoot string, localDev bool) error {
164→	hooksPath := filepath.Join(repoRoot, ".kiro", hooksDir, hooksFileName)
165→	if err := os.MkdirAll(filepath.Dir(hooksPath), 0o750); err != nil {
166→		return err
167→	}
168→	commandBase := hookCommandBase(localDev)
