300→func installTrustedCommands(repoRoot string, localDev bool) error {
301→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
302→
303→	settings, err := readSettings(settingsPath)
304→	if err != nil {
305→		return err
306→	}
307→	commands, err := readTrustedCommands(settings)
308→	if err != nil {
309→		return err
310→	}
311→	want := trustedCommand(localDev)
312→	for _, command := range commands {
313→		if command == want {
314→			return nil
315→		}
316→	}
317→	commands = append(commands, want)
318→	raw, err := json.Marshal(commands)
319→	if err != nil {
320→		return err
321→	}
322→	settings[trustedCommandsKey] = raw
323→	return writeSettings(settingsPath, settings)
324→}
