326→func uninstallTrustedCommands(repoRoot string) error {
327→	settingsPath := filepath.Join(repoRoot, vscodeSettingsDir, vscodeSettingsFile)
328→	if _, err := os.Stat(settingsPath); err != nil {
329→		if os.IsNotExist(err) {
330→			return nil
331→		}
332→		return err
333→	}
334→	settings, err := readSettings(settingsPath)
335→	if err != nil {
336→		return err
337→	}
338→	commands, err := readTrustedCommands(settings)
339→	if err != nil {
340→		return err
341→	}
342→	filtered := commands[:0]
343→	for _, command := range commands {
344→		if command != prodTrustedCommand && command != localDevTrustedCmd {
345→			filtered = append(filtered, command)
346→		}
347→	}
348→	if len(filtered) == 0 {
349→		delete(settings, trustedCommandsKey)
350→	} else {
351→		raw, err := json.Marshal(filtered)
352→		if err != nil {
353→			return err
354→		}
355→		settings[trustedCommandsKey] = raw
356→	}
357→	return writeSettings(settingsPath, settings)
358→}
