336→func isCLITranscript(transcript *kiroTranscript) bool {
337→	if len(transcript.History) == 0 {
338→		return false
339→	}
340→	return len(transcript.History[0].User.Content) > 0 || len(transcript.History[0].Assistant) > 0
341→}
342→
343→func tryParseIDETranscript(data []byte) *kiroTranscript {
344→	var ide kiroIDETranscript
345→	if err := json.Unmarshal(data, &ide); err != nil {
346→		return nil
347→	}
348→	if len(ide.History) == 0 || ide.History[0].Message.Role == "" {
349→		return nil
350→	}
351→	return convertIDETranscript(&ide)
352→}
353→
354→func convertIDETranscript(ide *kiroIDETranscript) *kiroTranscript {
355→	transcript := &kiroTranscript{}
356→
357→	var pendingUser *kiroIDEHistoryEntry
358→	for i := range ide.History {
359→		entry := &ide.History[i]
360→		switch entry.Message.Role {
361→		case "user":
362→			if pendingUser != nil {
363→				transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
364→			}
365→			pendingUser = entry
366→		case "assistant":
367→			transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, entry))
368→			pendingUser = nil
369→		}
370→	}
371→
372→	if pendingUser != nil {
373→		transcript.History = append(transcript.History, ideEntryToPaired(pendingUser, nil))
374→	}
375→
376→	return transcript
377→}
378→
379→func ideEntryToPaired(user, assistant *kiroIDEHistoryEntry) kiroHistoryEntry {
380→	entry := kiroHistoryEntry{}
381→
382→	if user != nil {
383→		prompt := extractIDEText(user.Message.Content, true)
384→		if prompt != "" {
385→			content, err := json.Marshal(kiroPromptContent{
386→				Prompt: struct {
387→					Prompt string `json:"prompt"`
388→				}{Prompt: prompt},
389→			})
390→			if err == nil {
391→				entry.User.Content = content
392→			}
393→		} else {
394→			entry.User.Content = user.Message.Content
395→		}
396→	}
397→
398→	if assistant != nil {
399→		text := extractIDEText(assistant.Message.Content, false)
400→		if text != "" {
401→			content, err := json.Marshal(kiroResponseContent{
402→				Response: kiroResponsePayload{Content: text},
403→			})
404→			if err == nil {
405→				entry.Assistant = content
406→			}
407→		} else {
408→			entry.Assistant = assistant.Message.Content
409→		}
410→	}
411→
412→	return entry
413→}
414→
415→// extractIDEText extracts text from a json.RawMessage that may be either a
416→// plain string or an array of content blocks. When blocksFirst is true, it
417→// tries to parse as blocks before falling back to a plain string (user
418→// messages); otherwise it tries plain string first (assistant messages).
419→func extractIDEText(content json.RawMessage, blocksFirst bool) string {
420→	if len(content) == 0 {
421→		return ""
422→	}
423→
424→	tryBlocks := func() string {
425→		var blocks []kiroIDEContentBlock
426→		if err := json.Unmarshal(content, &blocks); err == nil && len(blocks) > 0 {
427→			for _, block := range blocks {
428→				if block.Type == "text" && block.Text != "" {
429→					return block.Text
430→				}
431→			}
432→		}
433→		return ""
434→	}
435→
436→	tryString := func() string {
437→		var text string
438→		if err := json.Unmarshal(content, &text); err == nil {
439→			return text
440→		}
441→		return ""
442→	}
443→
444→	if blocksFirst {
445→		if s := tryBlocks(); s != "" {
446→			return s
447→		}
448→		return tryString()
449→	}
450→	if s := tryString(); s != "" {
451→		return s
452→	}
453→	return tryBlocks()
454→}
455→
456→func extractUserPrompt(content json.RawMessage) string {
457→	if len(content) == 0 {
458→		return ""
459→	}
460→
461→	var promptContent kiroPromptContent
462→	if err := json.Unmarshal(content, &promptContent); err == nil && promptContent.Prompt.Prompt != "" {
463→		return promptContent.Prompt.Prompt
464→	}
465→	return ""
466→}
