212→func HandleParseHook(args []string, stdin io.Reader, stdout io.Writer, parser hookParser) error {
213→	fs := flag.NewFlagSet("parse-hook", flag.ContinueOnError)
214→	fs.SetOutput(io.Discard)
215→	hook := fs.String("hook", "", "hook name")
216→	if err := fs.Parse(args); err != nil {
217→		return err
218→	}
219→	input, err := readStdinWithTimeout(stdin, 100*time.Millisecond)
220→	if err != nil {
221→		return err
222→	}
223→	event, err := parser.ParseHook(*hook, input)
224→	if err != nil {
225→		return err
226→	}
227→	if event == nil {
228→		_, err = io.WriteString(stdout, "null\n")
229→		return err
230→	}
231→	return WriteJSON(stdout, event)
232→}
